package com.archiveos.ai.memory;
import com.archiveos.ai.obsidian.Json; import java.sql.*; import java.util.*; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.stereotype.Repository;
@Repository public class MemoryRepository { private final JdbcTemplate jdbc; public MemoryRepository(JdbcTemplate jdbc){this.jdbc=jdbc;}
 public Map<String,Object> find(String id){List<Map<String,Object>> r=jdbc.query("select * from public.ai_memory_records where memory_id=?",this::row,id);return r.isEmpty()?null:r.get(0);} public Map<String,Object> findBySource(String id){List<Map<String,Object>> r=jdbc.query("select * from public.ai_memory_records where source_recommendation_id=?",this::row,id);return r.isEmpty()?null:r.get(0);} public List<Map<String,Object>> list(){return jdbc.query("select * from public.ai_memory_records order by created_at desc",this::row);}
 public Map<String,Object> create(Map<String,Object> v){return jdbc.queryForObject("insert into public.ai_memory_records(memory_id,source_recommendation_id,status,title,memory_type,service,correlation_id,entity_id,draft) values(?,?,?,?,?,?,?,?,?::jsonb) returning *",this::row,v.get("memoryId"),v.get("sourceId"),"DRAFT",v.get("title"),v.get("memoryType"),v.get("service"),v.get("correlationId"),v.get("entityId"),Json.write(v.get("draft")));}
 public Map<String,Object> approve(String id,String by,String reason){jdbc.update("update public.ai_memory_records set status='APPROVED',approved_by=?,approval_reason=?,updated_at=now() where memory_id=?",by,reason,id);return find(id);} public Map<String,Object> written(String id,String path,String hash){jdbc.update("update public.ai_memory_records set status='SYNC_PENDING',relative_path=?,content_hash=?,written_at=now(),updated_at=now() where memory_id=?",path,hash,id);return find(id);}
 private Map<String,Object> row(ResultSet r,int n)throws SQLException{Map<String,Object> v=new LinkedHashMap<>();for(String k:List.of("memory_id","source_recommendation_id","status","title","memory_type","service","correlation_id","entity_id","relative_path","content_hash","approved_by","approval_reason"))v.put(k,r.getString(k));v.put("draft",Json.readObjectArrayCompatible(r.getString("draft")));for(String k:List.of("written_at","created_at","updated_at")){Timestamp t=r.getTimestamp(k);v.put(k,t==null?null:t.toInstant().toString());}return v;}}
